import axios from 'axios'
import router from '../router/index'
import toolUtil from '@/utils/toolUtil'
import config from '@/utils/config'
import { ElMessage } from 'element-plus'

const http = axios.create({
    timeout: 1000 * 86400,
    withCredentials: true,
    baseURL: process.env.VUE_APP_BASE_API,
    headers: {
        'Content-Type': 'application/json; charset=utf-8'
    }
})

const requestCache = new Map()

http.interceptors.request.use(config => {
    const token = toolUtil.storageGet('Token')
    if (token) {
        config.headers['Token'] = token
    }

    const cacheKey = `${config.method}_${config.url}_${JSON.stringify(config.params || config.data)}`
    if (config.cache && requestCache.has(cacheKey)) {
        return Promise.resolve({ data: requestCache.get(cacheKey), fromCache: true })
    }

    config.metadata = { cacheKey, cache: config.cache }
    return config
}, error => {
    console.error('请求错误:', error)
    return Promise.reject(error)
})

http.interceptors.response.use(response => {
    const config = response.config

    if (config.metadata && config.metadata.cache) {
        requestCache.set(config.metadata.cacheKey, response.data)
    }

    if (response.data && response.data.code === 401) {
        toolUtil.storageClear()
        ElMessage.error(response.data.msg || '登录已过期，请重新登录')
        router.push('/login')
        return Promise.reject(response)
    }
    else if (response.data && response.data.code === 0) {
        return response
    } else {
        ElMessage.error(response.data.msg || '请求失败')
        return Promise.reject(response)
    }
}, error => {
    if (error.response) {
        const status = error.response.status
        if (status === 401) {
            toolUtil.storageClear()
            ElMessage.error('登录已过期，请重新登录')
            router.push('/login')
        } else if (status === 404) {
            ElMessage.error('请求的资源不存在')
        } else if (status === 500) {
            ElMessage.error('服务器内部错误')
        } else if (status >= 500) {
            ElMessage.error('服务器错误，请稍后重试')
        } else if (status >= 400) {
            ElMessage.error('请求参数错误')
        }
    } else if (error.code === 'ECONNABORTED') {
        ElMessage.warning('请求已取消')
    } else if (error.message.includes('timeout')) {
        ElMessage.error('请求超时，请检查网络连接')
    } else {
        ElMessage.error('网络错误，请检查网络连接')
    }
    return Promise.reject(error)
})

http.clearCache = () => {
    requestCache.clear()
}

export default http
